// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 3000
int n, m, k;
int graph[MAX_N][MAX_N];
int max_clique_size = 0;
void backtrack(int current_clique[], int current_size, int start)
{
    if (start == n) return;
    for (int i = start; i < n; i++) {
        int valid = 1;
        for (int j = 0; j < current_size; j++) {
            if (!graph[current_clique[j]][i]) {
                valid = 0;
                break;
            }
        }
        if (valid) {
            current_clique[current_size] = i;
            if (current_size + 1 >= max_clique_size && current_size + 1 >= k) {
                max_clique_size = current_size + 1;
            }
            backtrack(current_clique, current_size + 1, i + 1);
        }
    }
}
int main()
{
    scanf("%d %d %d", &n, &m, &k);
    for (int i = 0; i < m; i++) {
        int a, b;
        scanf("%d %d", &a, &b);
        graph[a - 1][b - 1] = 1;
        graph[b - 1][a - 1] = 1;
    }
    int current_clique[MAX_N];
    backtrack(current_clique, 0, 0);
    if (max_clique_size >= k) {
        printf("YES\n");
        printf("%d\n", max_clique_size);
    } else {
        printf("NO\n");
    }
    return 0;
}

