import java.util.Scanner;
public class Main {
    static final int MAX_N = 3000;
    static int n, m, k;
    static int[][] graph;
    static int max_clique_size = 0;
    public static void backtrack(int[] current_clique, int current_size, int start)
    {
        if (start == n) return;
        for (int i = start; i < n; i++) {
            int valid = 1;
            for (int j = 0; j < current_size; j++) {
                if (graph[current_clique[j]][i] == 0) {
                    valid = 0;
                    break;
                }
            }
            if (valid) {
                current_clique[current_size] = i;
                if (current_size + 1 >= max_clique_size && current_size + 1 >= k) {
                    max_clique_size = current_size + 1;
                }
                backtrack(current_clique, current_size + 1, i + 1);
            }
        }
    }
    public static void main(String[] args)
    {
        Scanner scanner = new Scanner(System.in);
        n = scanner.nextInt();
        m = scanner.nextInt();
        k = scanner.nextInt();
        graph = new int[n][n];
        for (int i = 0; i < m; i++) {
            int a = scanner.nextInt() - 1;
            int b = scanner.nextInt() - 1;
            graph[a][b] = 1;
            graph[b][a] = 1;
        }
        int[] current_clique = new int[n];
        backtrack(current_clique, 0, 0);
        if (max_clique_size >= k) {
            System.out.println("YES");
            System.out.println(max_clique_size);
        } else {
            System.out.println("NO");
        }
    }
}

